def setup_index_and_data(es_client, index_name="my_products_dynamic_scripts"):
    """
    Creates an index and adds sample data if they don't already exist.
    """
    if not es_client.indices.exists(index=index_name):
        print(f"Creating index '{index_name}'...")
        es_client.indices.create(index=index_name, body={
            "settings": {
                "number_of_shards": 1,
                "number_of_replicas": 0
            },
            "mappings": {
                "properties": {
                    "product_id": {"type": "keyword"},
                    "price": {"type": "double"},
                    "quantity": {"type": "integer"},
                    "category": {"type": "keyword"}
                }
            }
        })
        print(f"Index '{index_name}' created.")

        print("Indexing sample data...")
        docs = [
            {"product_id": "P001", "price": 10.50, "quantity": 2, "category": "Electronics"},
            {"product_id": "P002", "price": 20.00, "quantity": 1, "category": "Books"},
            {"product_id": "P003", "price": 5.25, "quantity": 4, "category": "Electronics"},
            {"product_id": "P004", "price": 12.75, "quantity": 3, "category": "Books"},
            {"product_id": "P005", "price": 15.00, "quantity": 2, "category": "Home Goods"},
        ]
        for i, doc in enumerate(docs):
            es_client.index(index=index_name, id=str(i+1), document=doc, refresh=True)
        print(f"{len(docs)} documents indexed.")
    else:
        print(f"Index '{index_name}' already exists.")

def execute_script_metric_aggregation(es_client, index_name, agg_name, script_source, script_params=None, metric_agg_type="sum"):
    """
    Executes an Elasticsearch metric aggregation (e.g., sum, avg, min, max)
    using a dynamic Painless script.

    NOTE: For inline scripts to work, 'script.inline: true' must be enabled
    in your Elasticsearch cluster settings. This is often done via:
    PUT _cluster/settings
    {
      "persistent": {
        "script.inline": "true",
        "script.painless.regex.enabled": "true"
      }
    }

    Args:
        es_client: The Elasticsearch client instance.
        index_name (str): The name of the index to search.
        agg_name (str): The name of the aggregation to use in the results.
        script_source (str): The Painless script code provided by the user.
        script_params (dict, optional): Optional parameters to pass to the script.
                                        Defaults to None.
        metric_agg_type (str, optional): The type of metric aggregation to apply the script to
                                         (e.g., "sum", "avg", "min", "max"). Defaults to "sum".
    Returns:
        dict: The aggregation results.
    """
    if script_params is None:
        script_params = {}

    # Construct the aggregation query for a metric aggregation with a script
    aggregations = {
        agg_name: {
            metric_agg_type: {
                "script": {
                    "source": script_source,
                    "lang": "painless",
                    "params": script_params
                }
            }
        }
    }

    print(f"\nExecuting '{metric_agg_type}' aggregation for index '{index_name}' with script:")
    print(json.dumps(aggregations, indent=2))

    try:
        # Use the 'aggregations' parameter directly for modern Elasticsearch client versions
        response = es_client.search(index=index_name, size=0, aggregations=aggregations)
        return response.get('aggregations', {})
    except Exception as e:
        print(f"Error executing script aggregation: {e}")
        return {}

